import type { BetterAuthClientPlugin } from "better-auth";
import type { BetterFetchResponse, BetterFetchOption, BetterFetch } from "@better-fetch/fetch";

import type { PaystackProduct, PaystackTransaction, Subscription } from "./types";

import type { paystack } from "./index";

export const paystackClient = <
	O extends {
		subscription: boolean;
	},
>(
		_options?: O,
	) => {
	return {
		id: "paystack",
		$InferServerPlugin: {} as ReturnType<typeof paystack>,
		getActions: ($fetch: any, _$store: any, _options: any) => {
			const fetch = $fetch as BetterFetch;
			const initializeTransaction = async (data: {
				plan?: string;
				email?: string;
				amount?: number;
				reference?: string;
				metadata?: Record<string, unknown>;
				callbackUrl?: string;
				callbackURL?: string;
				currency?: string;
				quantity?: number;
				referenceId?: string;
				product?: string;
				scheduleAtPeriodEnd?: boolean;
				cancelAtPeriodEnd?: boolean;
				prorateAndCharge?: boolean;
			}, options?: BetterFetchOption): Promise<BetterFetchResponse<{
				url: string;
				reference: string;
				accessCode: string;
				redirect: boolean;
			}>> => {
				return fetch<{
					url: string;
					reference: string;
					accessCode: string;
					redirect: boolean;
				}>("paystack/initialize-transaction", {
					method: "POST",
					body: data,
					...options,
				});
			};

			const verifyTransaction = async (data: { reference: string }, options?: BetterFetchOption): Promise<BetterFetchResponse<{
				status: string;
				reference: string;
				data: unknown;
			}>> => {
				return fetch<{
					status: string;
					reference: string;
					data: unknown;
				}>("paystack/verify-transaction", {
					method: "POST",
					body: data,
					...options,
				});
			};

			const listTransactions = async (data: { query?: Record<string, unknown> } = {}, options?: BetterFetchOption): Promise<BetterFetchResponse<{
				transactions: PaystackTransaction[];
			}>> => {
				return fetch<{
					transactions: PaystackTransaction[];
				}>("paystack/list-transactions", {
					method: "GET",
					query: data.query,
					...options,
				});
			};

			const listSubscriptions = async (data: { query?: Record<string, unknown> } = {}, options?: BetterFetchOption): Promise<BetterFetchResponse<{
				subscriptions: Subscription[];
			}>> => {
				return fetch<{
					subscriptions: Subscription[];
				}>("paystack/list-subscriptions", {
					method: "GET",
					query: data.query,
					...options,
				});
			};

			const getSubscriptionManageLink = async (data: { subscriptionCode: string }, options?: BetterFetchOption): Promise<BetterFetchResponse<{
				link: string;
			}>> => {
				return fetch<{
					link: string;
				}>("paystack/get-subscription-manage-link", {
					method: "GET",
					query: data,
					...options,
				});
			};

			const cancelSubscription = async (data: {
				subscriptionCode: string;
				emailToken?: string;
				atPeriodEnd?: boolean;
			}, options?: BetterFetchOption): Promise<BetterFetchResponse<{
				status: string;
			}>> => {
				return fetch<{
					status: string;
				}>("paystack/disable-subscription", {
					method: "POST",
					body: data,
					...options,
				});
			};

			const restoreSubscription = async (data: {
				subscriptionCode: string;
				emailToken?: string;
			}, options?: BetterFetchOption): Promise<BetterFetchResponse<{
				status: string;
			}>> => {
				return fetch<{
					status: string;
				}>("paystack/enable-subscription", {
					method: "POST",
					body: data,
					...options,
				});
			};

			return {
				subscription: {
					/**
					 * Initialize a transaction to upgrade or creating a subscription.
					 */
					upgrade: initializeTransaction,
					/**
					 * Initialize a payment to create a subscription.
					 */
					create: initializeTransaction,
					/**
					 * Disable a subscription.
					 */
					cancel: cancelSubscription,
					/**
					 * Enable a subscription.
					 */
					restore: restoreSubscription,
					/**
					 * List subscriptions for the user.
					 */
					list: listSubscriptions,
					/**
					 * Get a link to manage the subscription on Paystack.
					 */
					billingPortal: getSubscriptionManageLink,
					/**
					 * Aliases for legacy/demo usage.
					 */
					listLocal: listSubscriptions,
					manageLink: getSubscriptionManageLink,
					disable: cancelSubscription,
					enable: restoreSubscription,
				},
				paystack: {
					transaction: {
						initialize: initializeTransaction,
						verify: verifyTransaction,
						list: listTransactions,
					},
					subscription: {
						create: initializeTransaction,
						upgrade: initializeTransaction,
						cancel: cancelSubscription,
						restore: restoreSubscription,
						list: listSubscriptions,
						billingPortal: getSubscriptionManageLink,
						listLocal: listSubscriptions,
						manageLink: getSubscriptionManageLink,
						disable: cancelSubscription,
						enable: restoreSubscription,
					},
					initializeTransaction,
					verifyTransaction,
					listTransactions,
					listSubscriptions,
					getSubscriptionManageLink,
					getConfig: async (): Promise<BetterFetchResponse<Record<string, unknown>>> => {
						return fetch<Record<string, unknown>>("paystack/get-config", {
							method: "GET",
						});
					},
					syncProducts: async (): Promise<BetterFetchResponse<{ status: string; count: number }>> => {
						return fetch<{ status: string; count: number }>("paystack/sync-products", {
							method: "POST",
						});
					},
					syncPlans: async (): Promise<BetterFetchResponse<{ status: string; count: number }>> => {
						return fetch<{ status: string; count: number }>("paystack/sync-plans", {
							method: "POST",
						});
					},
					listProducts: async (options?: BetterFetchOption): Promise<BetterFetchResponse<{
						products: PaystackProduct[];
					}>> => {
						return fetch<{
							products: PaystackProduct[];
						}>("paystack/list-products", {
							method: "GET",
							...options,
						});
					},
					listPlans: async (options?: BetterFetchOption): Promise<BetterFetchResponse<{
						plans: unknown[];
					}>> => {
						return fetch<{
							plans: unknown[];
						}>("paystack/list-plans", {
							method: "GET",
							...options,
						});
					},
				},
			};
		}
	} satisfies BetterAuthClientPlugin;
};

import { defineErrorCodes } from "@better-auth/core/utils/error-codes";
import type { AuthContext, GenericEndpointContext } from "better-auth";
import { defu } from "defu";

import {
	disablePaystackSubscription,
	enablePaystackSubscription,
	initializeTransaction,
	listSubscriptions,
	listTransactions,
	paystackWebhook,
	verifyTransaction,
	getConfig,
	getSubscriptionManageLink,
	PAYSTACK_ERROR_CODES,
	createSubscription,
	upgradeSubscription,
	cancelSubscription,
	restoreSubscription,
	chargeRecurringSubscription,
	syncProducts,
	listProducts,
	syncPlans,
	listPlans,
} from "./routes";
import { getSchema } from "./schema";
import { checkSeatLimit, checkTeamLimit, getOrganizationSubscription } from "./limits";
import { getPlanByName, syncSubscriptionSeats } from "./utils";
import type {
	PaystackNodeClient,
	PaystackClientLike,
	PaystackOptions,
	PaystackPlan,
	Subscription,
	SubscriptionOptions,
	PaystackProduct,
	PaystackCustomerResponse,
} from "./types";
import { getPaystackOps, unwrapSdkResult } from "./paystack-sdk";

const INTERNAL_ERROR_CODES = defineErrorCodes({
	...Object.fromEntries(
		Object.entries(PAYSTACK_ERROR_CODES).map(([key, value]) => [
			key,
			typeof value === "string" ? value : (value as { message: string }).message,
		]),
	),
});

export const paystack = <
	TPaystackClient extends PaystackClientLike = PaystackNodeClient,
	TMetadata = Record<string, unknown>,
	TLimits = Record<string, unknown>,
	O extends PaystackOptions<TPaystackClient, TMetadata, TLimits> = PaystackOptions<TPaystackClient, TMetadata, TLimits>,
>(
		options: O,
	) => {
	// eslint-disable-next-line @typescript-eslint/no-explicit-any
	const routeOptions = options as any;
	const res = {
		id: "paystack",
		endpoints: {
			initializeTransaction: initializeTransaction(routeOptions),
			verifyTransaction: verifyTransaction(routeOptions),
			listSubscriptions: listSubscriptions(routeOptions),
			paystackWebhook: paystackWebhook(routeOptions),
			listTransactions: listTransactions(routeOptions),
			getConfig: getConfig(routeOptions),
			disableSubscription: disablePaystackSubscription(routeOptions),
			enableSubscription: enablePaystackSubscription(routeOptions),
			getSubscriptionManageLink: getSubscriptionManageLink(routeOptions),
			subscriptionManageLink: getSubscriptionManageLink(routeOptions, "/paystack/subscription/manage-link"), // Historical alias
			createSubscription: createSubscription(routeOptions),
			upgradeSubscription: upgradeSubscription(routeOptions),
			cancelSubscription: cancelSubscription(routeOptions),
			restoreSubscription: restoreSubscription(routeOptions),
			chargeRecurringSubscription: chargeRecurringSubscription(routeOptions),
			syncProducts: syncProducts(routeOptions),
			listProducts: listProducts(routeOptions),
			syncPlans: syncPlans(routeOptions),
			listPlans: listPlans(routeOptions),
		},
		schema: getSchema(options),
		init: (ctx: AuthContext) => {
			return {
				options: {
					databaseHooks: {
						user: {
							create: {
								async after(user: { id: string; email?: string | null; name?: string | null }, hookCtx?: GenericEndpointContext | null) {
									if (hookCtx === undefined || hookCtx === null || options.createCustomerOnSignUp !== true || !user.email) return;

									const paystackOps = getPaystackOps(options.paystackClient as PaystackClientLike);
									const raw = await paystackOps.customerCreate({
										email: user.email,
										first_name: user.name ?? undefined,
										metadata: {
											userId: user.id,
										} as Record<string, unknown>,
									});
									const sdkRes = unwrapSdkResult<PaystackCustomerResponse>(raw);
									const customerCode = (sdkRes?.customer_code as string | undefined)
										?? (sdkRes?.data as Record<string, unknown>)?.customer_code as string | undefined;

									if (customerCode === undefined || customerCode === null) {
										return;
									}
									await (ctx.adapter as any).update({
										model: "user",
										where: [{ field: "id", value: user.id }],
										update: {
											paystackCustomerCode: customerCode,
										},
									});
								},
							},
						},
						organization: options.organization?.enabled === true
							? {
								create: {
									async after(org: { id: string; name: string; email?: string | null }, hookCtx: GenericEndpointContext | null) {
										try {
											const extraCreateParams = options.organization?.getCustomerCreateParams
												? await options.organization.getCustomerCreateParams(org, hookCtx!)
												: {};

											let targetEmail = org.email;
											if (targetEmail === undefined || targetEmail === null) {
												const ownerMember = await (ctx.adapter as any).findOne({
													model: "member",
													where: [
														{ field: "organizationId", value: org.id },
														{ field: "role", value: "owner" }
													]
												});
												if (ownerMember !== null && ownerMember !== undefined) {
													const ownerUser = await (ctx.adapter as any).findOne({
														model: "user",
														where: [{ field: "id", value: ownerMember.userId }]
													});
													targetEmail = ownerUser?.email;
												}
											}

											if (targetEmail === undefined || targetEmail === null) return;

											const params = defu(
												{
													email: targetEmail,
													first_name: org.name,
													metadata: { organizationId: org.id },
												},
												extraCreateParams,
											);
											const paystackOps = getPaystackOps(options.paystackClient as PaystackClientLike);
											const raw = await paystackOps.customerCreate(params as unknown as Parameters<typeof paystackOps.customerCreate>[0]);
											const sdkRes = unwrapSdkResult<PaystackCustomerResponse>(raw);
											const customerCode = (sdkRes?.customer_code as string | undefined)
												?? (sdkRes?.data as Record<string, unknown>)?.customer_code as string | undefined;

											if (customerCode === undefined || customerCode === null) return;

											// eslint-disable-next-line @typescript-eslint/no-explicit-any
											await (ctx.internalAdapter as any).updateOrganization(org.id, {
												paystackCustomerCode: customerCode,
											});

											await options.organization?.onCustomerCreate?.(
												{
													paystackCustomer: sdkRes as unknown as PaystackCustomerResponse,
													organization: {
														...org,
														paystackCustomerCode: customerCode,
													},
												},
												hookCtx!,
											);
										} catch (error: unknown) {
											(ctx as unknown as AuthContext).logger.error("Failed to create Paystack customer for organization", error);
										}
									},
								},
							}
							: undefined,
					},
					member: {
						create: {
							before: async (member: { organizationId: string }, ctx: GenericEndpointContext | null | undefined) => {
								if (options.subscription?.enabled === true && member.organizationId && ctx !== null && ctx !== undefined) {
									await checkSeatLimit(ctx, member.organizationId);
								}
							},
							after: async (member: { organizationId: string | undefined }, ctx: GenericEndpointContext | null | undefined) => {
								if (options.subscription?.enabled === true && (member?.organizationId !== undefined && member?.organizationId !== null) && (ctx !== undefined && ctx !== null)) {
									await syncSubscriptionSeats(ctx, member.organizationId, options);
								}
							},
						},
						delete: {
							after: async (member: { organizationId: string | undefined }, ctx: GenericEndpointContext | null | undefined) => {
								if (options.subscription?.enabled === true && (member?.organizationId !== undefined && member?.organizationId !== null) && (ctx !== undefined && ctx !== null)) {
									await syncSubscriptionSeats(ctx, member.organizationId, options);
								}
							},
						}
					},
					invitation: {
						create: {
							before: async (invitation: { organizationId: string }, ctx: GenericEndpointContext | null | undefined) => {
								if (options.subscription?.enabled === true && invitation.organizationId && ctx !== null && ctx !== undefined) {
									await checkSeatLimit(ctx, invitation.organizationId);
								}
							},
							after: async (invitation: { organizationId: string | undefined }, ctx: GenericEndpointContext | null | undefined) => {
								if (options.subscription?.enabled === true && (invitation?.organizationId !== undefined && invitation?.organizationId !== null) && (ctx !== undefined && ctx !== null)) {
									await syncSubscriptionSeats(ctx, invitation.organizationId, options);
								}
							},
						},
						delete: {
							after: async (invitation: { organizationId: string | undefined }, ctx: GenericEndpointContext | null | undefined) => {
								if (options.subscription?.enabled === true && (invitation?.organizationId !== undefined && invitation?.organizationId !== null) && (ctx !== undefined && ctx !== null)) {
									await syncSubscriptionSeats(ctx, invitation.organizationId, options);
								}
							},
						}
					},
					team: {
						create: {
							before: async (team: { organizationId: string }, ctx: GenericEndpointContext | null | undefined) => {
								if (options.subscription?.enabled === true && team.organizationId && ctx !== null && ctx !== undefined) {
									const subscription = await getOrganizationSubscription(ctx, team.organizationId);
									if (subscription !== null && subscription !== undefined) {
										const plan = await getPlanByName(options, subscription.plan);
										const limits = plan?.limits;
										const maxTeams = limits?.teams as number | undefined;

										if (typeof maxTeams === "number") {
											await checkTeamLimit(ctx, team.organizationId, maxTeams);
										}
									}
								}
							},
						},
					},
				},
			};
		},
		$ERROR_CODES: INTERNAL_ERROR_CODES,
	};

	return res;
};

export type PaystackPlugin<
	// eslint-disable-next-line @typescript-eslint/no-explicit-any
	O extends PaystackOptions<PaystackClientLike, any, any> = PaystackOptions,
> = ReturnType<
	// eslint-disable-next-line @typescript-eslint/no-explicit-any
	typeof paystack<PaystackClientLike, any, any, O>
>;

export type { Subscription, SubscriptionOptions, PaystackPlan, PaystackOptions, PaystackProduct };

import type { GenericEndpointContext } from "better-auth";
import { APIError } from "better-auth/api";

import type { Subscription } from "./types";

export const getOrganizationSubscription = async (
	ctx: GenericEndpointContext,
	organizationId: string
): Promise<Subscription | null> => {
	const subscription = await  (ctx.context.adapter as any).findOne({
		model: "subscription",
		where: [{ field: "referenceId", value: organizationId }],
	});
	return subscription;
};

export const checkSeatLimit = async (
	ctx: GenericEndpointContext,
	organizationId: string,
	seatsToAdd = 1
) => {
	const subscription = await getOrganizationSubscription(ctx, organizationId);

	if (subscription?.seats === undefined || subscription.seats === null) {
		return true; // No explicit seat limit found
	}

	const members = await ctx.context.adapter.findMany({
		model: "member",
		where: [{ field: "organizationId", value: organizationId }],
	});

	if (members.length + seatsToAdd > subscription.seats) {
		throw new APIError("FORBIDDEN", {
			message: `Organization member limit reached. Used: ${members.length}, Max: ${subscription.seats}`
		});
	}

	return true;
};

export const checkTeamLimit = async (
	ctx: GenericEndpointContext,
	organizationId: string,
	maxTeams: number
) => {
	const teams = await ctx.context.adapter.findMany({
		model: "team",
		where: [{ field: "organizationId", value: organizationId }],
	});

	if (teams.length >= maxTeams) {
		throw new APIError("FORBIDDEN", {
			message: `Organization team limit reached. Max teams: ${maxTeams}`
		});
	}

	return true;
};

import { createAuthMiddleware } from "@better-auth/core/api";
import { logger } from "better-auth";
import { APIError } from "better-auth/api";


import type { PaystackClientLike, PaystackOptions, Session, User } from "./types";

export const referenceMiddleware = (
	options: PaystackOptions<PaystackClientLike>,
	action:
        | "initialize-transaction"
        | "verify-transaction"
        | "list-subscriptions"
        | "list-transactions"
        | "disable-subscription"
        | "enable-subscription"
        | "get-subscription-manage-link",
) =>
	createAuthMiddleware(async (ctx) => {
		const session = ctx.context.session as {
			user: User;
			session: Session;
		} | null;

		if (session === null || session === undefined) {
			throw new APIError("UNAUTHORIZED");
		}
		const body = (ctx.body ?? {}) as Record<string, unknown>;
		const query = (ctx.query ?? {}) as Record<string, unknown>;
		const referenceId =
            (body.referenceId as string | undefined) ?? (query.referenceId as string | undefined) ?? session.user.id;

		const subscriptionOptions = options.subscription;



		if (referenceId === session.user.id) {
			return {
				referenceId,
			};
		}



		// 1. Try custom authorization first if provided
		if (subscriptionOptions?.enabled === true && 'authorizeReference' in subscriptionOptions && subscriptionOptions.authorizeReference) {
			const authorized = await subscriptionOptions.authorizeReference(
				{
					user: session.user,
					session: session.session,
					referenceId,
					action,
				},
				ctx,
			);
			if (authorized === true) {
				return {
					referenceId,
				};
			}
			// If explicit authorizeReference returns false, do we fail immediately?
			// Usually yes, but maybe we fallback to org check?
			// Let's assume authorizeReference overrides everything.
			throw new APIError("UNAUTHORIZED");
		}

		// 2. Fallback: Organization Check
		if (options.organization?.enabled === true) {
			// Check if referenceId indicates an organization the user is a member of
			const member = await  (ctx.context.adapter as any).findOne({
				model: "member",
				where: [
					{ field: "userId", value: session.user.id },
					{ field: "organizationId", value: referenceId }
				]
			});

			if (member !== null && member !== undefined) {
				logger.debug("DEBUG MIDDLEWARE MEMBER FOUND:", member);
				// User is a member of the organization.
				// We could check roles here, but for now allow any member.
				return {
					referenceId,
				};
			}
		}

		logger.error(
			`Passing referenceId into a subscription action isn't allowed if subscription.authorizeReference isn't defined in your paystack plugin config and matches no organization membership.`,
		);
		throw new APIError("BAD_REQUEST", {
			message:
                "Passing referenceId isn't allowed without subscription.authorizeReference or valid organization membership.",
		});
	});

import type {
	PaystackClientLike,
	PaystackCustomerCreateInput,
	PaystackCustomerUpdateInput,
	PaystackNodeClient,
	PaystackOpenApiFetchResponse,
	PaystackSubscriptionFetchInit,
	PaystackSubscriptionCreateInput,
	PaystackSubscriptionToggleInput,
	PaystackTransactionInitializeInput,
	PaystackTransactionChargeAuthorizationInput,
} from "./types";

function isOpenApiFetchResponse(
	value: unknown,
): value is PaystackOpenApiFetchResponse {
	return (
		value !== null &&
		value !== undefined &&
		typeof value === "object" &&
		("data" in value || "error" in value || "response" in value)
	);
}

export function unwrapSdkResult<T = unknown>(result: unknown): T {
	if (isOpenApiFetchResponse(result)) {
		if (result.error !== undefined && result.error !== null) {
			throw new Error(typeof result.error === "string" ? result.error : JSON.stringify(result.error));
		}
		return (result.data as T) ?? (result as T);
	}
	if (result !== null && result !== undefined && typeof result === "object" && "data" in result) {
		const data = (result as { data: unknown }).data;
		// If data is also an object with a data property, unwrap it (legacy SDK style)
		if (data !== null && typeof data === "object" && "data" in data) {
			return (data as { data: T }).data;
		}
		return data as T;
	}
	return result as T;
}





type TransactionInitializeBody = Parameters<PaystackNodeClient["transaction_initialize"]>[0] extends {
	body?: infer B;
}
	? B
	: never;

export function getPaystackOps(
	paystackClient: PaystackClientLike,
) {
	return {
		customerCreate: (params: PaystackCustomerCreateInput) => {
			if (paystackClient?.customer_create !== undefined) {
				return paystackClient.customer_create({ body: params as unknown as NonNullable<Parameters<PaystackNodeClient["customer_create"]>[0]>["body"] });
			}
			return paystackClient?.customer?.create?.(params);
		},
		customerUpdate: (code: string, params: PaystackCustomerUpdateInput) => {
			if (paystackClient?.customer_update !== undefined) {
				return paystackClient.customer_update({
					params: { path: { code } },
					body: params as unknown as NonNullable<Parameters<PaystackNodeClient["customer_update"]>[0]>["body"],
				});
			}
			return paystackClient?.customer?.update?.(code, params);
		},
		transactionInitialize: (body: PaystackTransactionInitializeInput) => {
			if (paystackClient?.transaction_initialize !== undefined) {
				return paystackClient.transaction_initialize({
					body: body as TransactionInitializeBody,
				});
			}
			return paystackClient?.transaction?.initialize?.(body);
		},
		transactionVerify: (reference: string) => {
			if (paystackClient?.transaction_verify !== undefined) {
				return paystackClient.transaction_verify({
					params: { path: { reference } },
				});
			}
			return paystackClient?.transaction?.verify?.(reference);
		},
		subscriptionCreate: (body: PaystackSubscriptionCreateInput) => {
			if (paystackClient?.subscription_create !== undefined) {
				return paystackClient.subscription_create({ body });
			}
			return paystackClient?.subscription?.create?.(body);
		},
		subscriptionDisable: (body: PaystackSubscriptionToggleInput) => {
			if (paystackClient?.subscription_disable !== undefined) {
				return paystackClient.subscription_disable({ body });
			}
			return paystackClient?.subscription?.disable?.(body);
		},
		subscriptionEnable: (body: PaystackSubscriptionToggleInput) => {
			if (paystackClient?.subscription_enable !== undefined) {
				return paystackClient.subscription_enable({ body });
			}
			return paystackClient?.subscription?.enable?.(body);
		},
		subscriptionFetch: async (idOrCode: string) => {
			if (paystackClient?.subscription_fetch !== undefined) {
				try {
					return await paystackClient.subscription_fetch({
						params: { path: { code: idOrCode } },
					});
				} catch {
					const compatFetch = paystackClient.subscription_fetch as unknown as (
						init: PaystackSubscriptionFetchInit,
					) => Promise<unknown>;
					return compatFetch({
						params: { path: { id_or_code: idOrCode } },
					});
				}
			}
			return paystackClient?.subscription?.fetch?.(idOrCode);
		},
		subscriptionManageLink: (code: string) => {
			if (paystackClient?.subscription_manageLink !== undefined) {
				return paystackClient.subscription_manageLink({
					params: { path: { code } },
				});
			}
			// Fallback for snake_case if older SDK version or different generator
			if (paystackClient?.subscription_manage_link !== undefined) {
				return paystackClient.subscription_manage_link({
					params: { path: { code } },
				});
			}
			return paystackClient?.subscription?.manage?.link?.(code);
		},
		subscriptionManageEmail: (code: string, email: string) => {
			if (paystackClient?.subscription_manageEmail !== undefined) {
				return paystackClient.subscription_manageEmail({
					params: { path: { code } },
				});
			}
			return paystackClient?.subscription?.manage?.email?.(code, email);
		},
		subscriptionUpdate: (params: { code: string; plan?: string; authorization?: string; amount?: number }) => {
			if (paystackClient?.subscription_update !== undefined) {
				return (paystackClient.subscription_update as any)({
					params: { path: { code: params.code } },
					body: {
						plan: params.plan,
						authorization: params.authorization,
						amount: params.amount,
					},
				});
			}
			// eslint-disable-next-line @typescript-eslint/no-explicit-any
			return (paystackClient as any)?.subscription?.update?.(params.code, params);
		},
		transactionChargeAuthorization: (body: PaystackTransactionChargeAuthorizationInput) => {
			if (paystackClient?.transaction_chargeAuthorization !== undefined) {
				return paystackClient.transaction_chargeAuthorization({

					// casting to avoid deep type issues with metadata
					// eslint-disable-next-line @typescript-eslint/no-explicit-any
					body: body as any, // casting to avoid deep type issues with metadata
				});
			}
			// eslint-disable-next-line @typescript-eslint/no-explicit-any
			return paystackClient?.transaction?.chargeAuthorization?.(body as any);
		},
		productList: () => {
			if (paystackClient?.product_list !== undefined) {
				return paystackClient.product_list();
			}
			return paystackClient?.product?.list?.();
		},
		productFetch: (idOrCode: string) => {
			if (paystackClient?.product_fetch !== undefined) {
				return paystackClient.product_fetch({
					params: { path: { id_or_code: idOrCode } },
				});
			}
			return paystackClient?.product?.fetch?.(idOrCode);
		},
		productCreate: (params: Record<string, unknown>) => {
			if (paystackClient?.product_create !== undefined) {
				return paystackClient.product_create({ body: params });
			}
			return paystackClient?.product?.create?.(params);
		},
		productUpdate: (idOrCode: string, params: Record<string, unknown>) => {
			if (paystackClient?.product_update !== undefined) {
				return paystackClient.product_update({
					params: { path: { id_or_code: idOrCode } },
					body: params,
				});
			}
			return paystackClient?.product?.update?.(idOrCode, params);
		},
		productDelete: (idOrCode: string) => {
			if (paystackClient?.product_delete !== undefined) {
				return paystackClient.product_delete({
					params: { path: { id_or_code: idOrCode } },
				});
			}
			return paystackClient?.product?.delete?.(idOrCode);
		},
		planList: () => {
			if (paystackClient?.plan_list !== undefined) {
				return paystackClient.plan_list();
			}
			return paystackClient?.plan?.list?.();
		},
	};
}

